SELECT MAX(score) AS max_score
FROM metric_scores
WHERE metric_id = 1 AND year = 2023;

SELECT MAX(overall_score) AS highest_overall_score
FROM country_scores
WHERE year = 2023;

SELECT AVG(freedom_and_openness) AS average_freedom_and_openness_score
FROM country_scores
WHERE year = 2023;

SELECT overall_score
FROM country_scores
WHERE year = 2023;
